def sum_within_depth(spec: dict) -> int:
    """Sum node values lying at most 'depth' hops from start."""
    nodes = spec["nodes"]; start = spec["start"]; cap = spec["depth"]
    depth = {start: 0}; queue = [start]; i = 0; total = 0
    while i < len(queue):
        n = queue[i]; i += 1
        total += nodes[n]["val"]
        if depth[n] < cap:
            for t in nodes[n]["to"]:
                if t not in depth:
                    depth[t] = depth[n] + 1
                    queue.append(t)
    return total
```

