    has best: str = "";
    has bl: int = 0;
    has seen: bool = False;
    can start with Feed entry { visit [-->][?:User]; }
    can seek with User entry { visit [-->][?:Post]; }
    can judge with Post entry {
        if not self.seen or here.likes > self.bl or (here.likes == self.bl and here.author < self.best) {
